<template>
  <UContextMenu
    ref="contextMenuRef"
    size="md"
    :items="contextMenuItems"
    :ui="{
      content: 'w-48',
    }"
  >
    <div
      class="file-card"
      :class="{ selected }"
      :data-id="file.id"
      @click="$emit('events', { name: 'click', data: $event })"
      @dblclick="$emit('events', { name: 'dblclick', data: $event })"
    >
      <div class="file-card-header">
        <UBadge color="neutral" variant="outline">PDF</UBadge>

        <div class="card-menu">
          <UButton
            class="card-menu rounded-3xl relative z-100"
            color="neutral"
            variant="ghost"
            icon="lucide:ellipsis-vertical"
            size="sm"
            @click="openMenu"
          />
        </div>
      </div>

      <div class="file-card-content">
        <img
          alt=""
          src="data:image/png;base64,"
        />
      </div>

      <div class="file-card-footer">
        <p class="card-name">{{ shortFileName(file.originalName, 25) }}</p>
      </div>
    </div>
  </UContextMenu>
</template>

<script setup lang="ts">
import type { ContextMenuItem } from "@nuxt/ui";

const props = defineProps({
  file: { type: Object, required: true },
  selected: { type: Boolean, default: false },
});

const emit = defineEmits(["events"]);

const contextMenuRef = ref(null);

const openMenu = (event: MouseEvent) => {
  const customEvent = new MouseEvent("contextmenu", {
    bubbles: true,
    cancelable: true,
    clientX: event.clientX,
    clientY: event.clientY,
  });

  if (event) {
    event?.currentTarget?.dispatchEvent(customEvent);
  }
};

const contextMenuItems = ref<ContextMenuItem[]>([
  {
    label: "Download",
    icon: "material-symbols:download-2-outline-rounded",
    onSelect: () => {
      emit("events", {
        name: "download",
        data: { id: props.file.id },
      });
    },
  },
  {
    label: "Rename",
    icon: "material-symbols:edit-outline-rounded",
    onSelect: () => {
      emit("events", {
        name: "update",
        data: { id: props.file.id },
      });
    },
  },
  {
    label: "Move to trash",
    icon: "material-symbols:restore-from-trash-outline-rounded",
    onSelect: () => {
      emit("events", {
        name: "delete",
        data: { id: props.file.id },
      });
    },
  },
]);
</script>

